254→void ALFPWorldMapPlayerController::OnCancelAction(const FInputActionValue& Value)
255→{
256→	// 取消选中和可达高亮
257→	ClearReachableHighlight();
258→	if (SelectedNode)
259→	{
260→		SelectedNode->SetHighlighted(false);
261→		SelectedNode = nullptr;
262→	}
263→}
264→
265→void ALFPWorldMapPlayerController::OnToggleEditorAction(const FInputActionValue& Value)
266→{
267→	if (!WorldMapEditorComponent) return;
268→
269→	WorldMapEditorComponent->ToggleEditorMode();
270→
271→	if (WorldMapEditorComponent->IsEditorActive())
272→	{
273→		// 创建或显示编辑器 Widget
274→		if (!WorldMapEditorWidget && WorldMapEditorWidgetClass)
275→		{
276→			WorldMapEditorWidget = CreateWidget<ULFPWorldMapEditorWidget>(this, WorldMapEditorWidgetClass);
277→			if (WorldMapEditorWidget)
278→			{
279→				WorldMapEditorWidget->AddToViewport();
280→				WorldMapEditorWidget->InitializeEditor(WorldMapEditorComponent);
281→			}
282→		}
283→		else if (WorldMapEditorWidget)
284→		{
285→			WorldMapEditorWidget->SetVisibility(ESlateVisibility::Visible);
286→		}
287→
288→		bShowMouseCursor = true;
289→	}
290→	else
291→	{
292→		// 隐藏编辑器 Widget
293→		if (WorldMapEditorWidget)
294→		{
295→			WorldMapEditorWidget->SetVisibility(ESlateVisibility::Collapsed);
296→		}
297→	}
298→}
