302→void ALFPWorldMapPlayerController::OnCameraPan(const FInputActionValue& Value)
303→{
304→	FVector2D PanInput = Value.Get<FVector2D>();
305→	CameraOffset += FVector(PanInput.X, PanInput.Y, 0) * CameraPanSpeed * GetWorld()->GetDeltaSeconds();
306→}
