221→FString ULFPShopWidget::BuildEffectDescription(const FLFPRelicDefinition& Definition) const
222→{
223→	TArray<FString> Parts;
224→	for (const FLFPRelicEffectEntry& Effect : Definition.Effects)
225→	{
226→		switch (Effect.EffectType)
227→		{
228→		case ELFPRelicEffectType::RET_MaxHealthFlat:
229→			Parts.Add(FString::Printf(TEXT("最大生命 %+d"), Effect.Value));
230→			break;
231→		case ELFPRelicEffectType::RET_AttackFlat:
232→			Parts.Add(FString::Printf(TEXT("攻击力 %+d"), Effect.Value));
233→			break;
234→		case ELFPRelicEffectType::RET_DefenseFlat:
235→			Parts.Add(FString::Printf(TEXT("防御力 %+d"), Effect.Value));
236→			break;
237→		case ELFPRelicEffectType::RET_SpeedFlat:
