217→void ULFPGameInstance::ApplyOwnedRelicsToUnit(ALFPTacticsUnit* Unit) const
218→{
219→	if (!Unit || !RelicDataAsset)
220→	{
221→		return;
222→	}
223→
224→	for (const FName& RelicID : OwnedRelicIDs)
225→	{
226→		FLFPRelicDefinition Definition;
227→		if (!FindRelicDefinition(RelicID, Definition))
228→		{
229→			continue;
230→		}
231→
232→		for (const FLFPRelicEffectEntry& Effect : Definition.Effects)
233→		{
234→			switch (Effect.EffectType)
235→			{
236→			case ELFPRelicEffectType::RET_MaxHealthFlat:
237→				Unit->AddCurrentMaxHealth(Effect.Value);
238→				break;
239→			case ELFPRelicEffectType::RET_AttackFlat:
240→				Unit->AddCurrentAttack(Effect.Value);
241→				break;
242→			case ELFPRelicEffectType::RET_DefenseFlat:
243→				Unit->AddCurrentPhysicalBlock(Effect.Value);
244→				break;
245→			case ELFPRelicEffectType::RET_SpeedFlat:
246→				Unit->AddCurrentSpeed(Effect.Value);
247→				break;
248→			default:
249→				break;
250→			}
251→		}
252→	}
253→}
